// Fetch last 24h of webhook executions from n8n internal API
const apiKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJzdWIiOiI3ZjU3OGYzNy1kMDVlLTQ1YzMtOTJjNC1hZmE3NzkzNzY4MzkiLCJpc3MiOiJuOG4iLCJhdWQiOiJwdWJsaWMtYXBpIiwianRpIjoiZmQyNzI5MzMtZTRhZi00YTkwLTkyMzUtMWZiZTc0YmQ5NzIzIiwiaWF0IjoxNzcyNjQyODE1fQ.It-V1MgIzXPSjMd_bX_8A126iU6rG6_KY-_3kgFyDRI';
const since = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString();

const resp = await this.helpers.httpRequest({
  method: 'GET',
  url: 'http://localhost:5678/api/v1/executions?limit=100',
  headers: { 'X-N8N-API-KEY': apiKey }
});

const allExecs = resp.data || resp || [];
const executions = allExecs.filter(e => e.startedAt && new Date(e.startedAt) >= new Date(since));

const toolWorkflows = ['Music Bot', 'minecraft', 'Docker Control', 'self_healing', 'Capabilities'];
const toolCalls = executions.filter(e =>
  toolWorkflows.some(n => (e.workflowName || '').toLowerCase().includes(n.toLowerCase()))
);
const errors = executions.filter(e => e.status === 'error');

return {
  json: {
    period: `${since} to ${new Date().toISOString()}`,
    totalExecutions: executions.length,
    successful: executions.filter(e => e.status === 'success').length,
    failed: errors.length,
    errorDetails: errors.slice(0, 10).map(e => ({
      workflow: e.workflowName || e.workflowId,
      startedAt: e.startedAt
    })),
    toolCallCount: toolCalls.length,
    summary: `${executions.length} executions (${executions.filter(e => e.status === 'success').length} ok, ${errors.length} errors) in last 24h. ${toolCalls.length} tool-related.`
  }
};

// Call Ollama Qwen3 32B for Architect analysis
const inputData = $input.first().json;
const NL = String.fromCharCode(10);

const systemLines = [
  "You are the Atlas Architect, a senior AI that reviews the Atlas Operator performance and proposes improvements.",
  "You analyze execution data and output structured JSON proposals.",
  "",
  "Output ONLY valid JSON with this structure:",
  '{ "analysis": "brief summary", "proposals": [ { "category": "safe|risky|blocked", "toolAffected": "tool_name", "description": "what to change", "diff": "specific change" } ], "healthScore": 0-100 }',
  "",
  "Categories:",
  "- safe: Knowledge base updates, tool description tweaks, documentation",
  "- risky: System prompt changes, new tool definitions, behavioral changes",
  "- blocked: Removing safety rules, disabling tools",
  "",
  "If everything looks good, return empty proposals array with a positive analysis. /no_think"
];
const systemPrompt = systemLines.join(NL);
const userPrompt = "Review the Atlas Operator performance for the last 24 hours:" + NL + NL + JSON.stringify(inputData, null, 2);

const body = {
  model: "qwen3:32b",
  messages: [
    { role: "system", content: systemPrompt },
    { role: "user", content: userPrompt }
  ],
  temperature: 0.3,
  max_tokens: 2000
};

const response = await this.helpers.httpRequest({
  method: "POST",
  url: "http://ollama:11434/v1/chat/completions",
  body: body,
  json: true,
  timeout: 180000,
  headers: {
    "Content-Type": "application/json"
  }
});

return { json: response };

// Parse Architect response and classify proposals
const response = $input.first().json;
let content = "";
try {
  const choices = response.choices || [];
  if (choices.length > 0) {
    content = choices[0].message?.content || "";
  }
} catch(e) {
  return { json: { error: "Failed to parse Architect response", raw: JSON.stringify(response).substring(0, 500) } };
}

// Extract JSON from response (may be wrapped in markdown code blocks)
let parsed;
try {
  // Use RegExp constructor to avoid newline issues in regex literals
  const codeBlockRe = new RegExp("```json\s*([\s\S]*?)\s*```");
  const jsonObjRe = new RegExp("(\{[\s\S]*\})");
  const jsonMatch = content.match(codeBlockRe) || content.match(jsonObjRe);
  parsed = JSON.parse(jsonMatch ? jsonMatch[1] : content);
} catch(e) {
  return { json: { error: "Failed to parse JSON from Architect", raw: content.substring(0, 500) } };
}

const proposals = parsed.proposals || [];
const analysis = parsed.analysis || "No analysis provided";
const healthScore = parsed.healthScore || 0;

// Log to SpacetimeDB
const stdbUrl = "http://stdb_backend:3000/v1/database/atlas/call";
const execData = $("Collect Execution Data").first().json;

try {
  await this.helpers.httpRequest({
    method: "POST",
    url: stdbUrl + "/record_daily_metrics",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      date: new Date().toISOString().split("T")[0],
      totalToolCalls: execData.toolCallCount || 0,
      successfulCalls: execData.successful || 0,
      failedCalls: execData.failed || 0,
      avgLatencyMs: 0,
      promptfooScore: 100.0,
      topFailedTool: "none"
    })
  });
} catch(e) { console.log("STDB metrics write failed:", e.message); }

for (const p of proposals) {
  try {
    await this.helpers.httpRequest({
      method: "POST",
      url: stdbUrl + "/submit_proposal",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        category: p.category || "safe",
        toolAffected: p.toolAffected || "general",
        description: p.description || "",
        diff: p.diff || "",
        evalScoreBefore: 100.0
      })
    });
  } catch(e) { console.log("STDB proposal write failed:", e.message); }
}

try {
  await this.helpers.httpRequest({
    method: "POST",
    url: stdbUrl + "/log_event",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      severity: "info",
      service: "architect-review",
      payload: JSON.stringify({ analysis, healthScore, proposalCount: proposals.length })
    })
  });
} catch(e) {}

return {
  json: {
    analysis,
    healthScore,
    proposals,
    safeCount: proposals.filter(p => p.category === "safe").length,
    riskyCount: proposals.filter(p => p.category === "risky").length,
    blockedCount: proposals.filter(p => p.category === "blocked").length,
    metricsLogged: true
  }
};

// Format the review summary for the webhook response
const data = $input.first().json;

let report = `# Architect Review â€” ${new Date().toISOString().split('T')[0]}\n\n`;
report += `**Health Score:** ${data.healthScore}/100\n`;
report += `**Analysis:** ${data.analysis}\n\n`;

if (data.proposals && data.proposals.length > 0) {
  report += `## Proposals (${data.proposals.length})\n\n`;
  for (const p of data.proposals) {
    const icon = p.category === 'safe' ? 'âœ…' : p.category === 'risky' ? 'âš ï¸�' : 'ðŸš«';
    report += `${icon} **[${p.category.toUpperCase()}]** ${p.toolAffected}: ${p.description}\n`;
    if (p.diff) report += `   â†’ ${p.diff}\n`;
    report += '\n';
  }
  report += `Safe: ${data.safeCount} | Risky: ${data.riskyCount} | Blocked: ${data.blockedCount}\n`;
} else {
  report += '**No proposals â€” system is healthy.**\n';
}

report += `\n_Logged to SpacetimeDB._`;

return { json: { report, ...data } };

// No proposals â€” system is healthy
const data = $input.first().json;
return {
  json: {
    report: `# Architect Review â€” ${new Date().toISOString().split('T')[0]}\n\n**Health Score:** ${data.healthScore}/100\n**Analysis:** ${data.analysis}\n\n**No proposals â€” system is healthy.**\n\n_Logged to SpacetimeDB._`,
    ...data
  }
};
